以下是一个简单的JavaScript代码，用于在用户点击按钮时显示一个弹出窗口：

```javascript
// 获取要触发事件的元素（这里是id为"myButton"的按钮）
var button = document.getElementById("myButton");

// 添加点击事件监听器
button.addEventListener("click", function() {
    // 创建一个新的div来作为弹出窗口的内容
    var popupWindow = document.createElement('div');
    popupWindow.style.position = 'absolute';
    popupWindow.style.top = '50px';  // 设置弹出窗口的位置
    popupWindow.style.left = '100px';  // 设置弹出窗口的位置
    popupWindow.style.width = '200px';  // 设置弹出窗口的宽度
    popupWindow.style.height = '100px';  // 设置弹出窗口的高度
    popupWindow.style.backgroundColor = '#f0f0f0';  // 设置背景颜色
    popupWindow.style.borderRadius = '5px';  // 设置圆角边框

    // 在弹出窗口中添加一些内容
    var content = document.createTextNode('这是一个弹出窗口！');
    popupWindow.appendChild(content);

    // 将弹出窗口添加到页面上
    document.body.appendChild(popupWindow);
});
```

这段代码首先获取了一个具有id为"myButton"的按钮元素，然后为其添加了一个点击事件监听器。当用户点击这个按钮时，它会创建一个新的div，并将这个div设置为弹出窗口的内容。然后，它会在页面上添加这个弹出窗口。

